import pytest
import requests

BASE_URL = "http://hr-app/api"

def test_update_policy_document_forbidden_role_returns_403(
    viewer_token,      # <fixture> returns JWT for viewer role
    existing_doc_id,   # <fixture>
):
    headers = {"Authorization": f"Bearer {viewer_token}"}
    payload = {
        "title": "Viewer Attempt",
        "content": "Should be denied.",
        "effective_date": "2025-01-01"
    }
    resp = requests.put(
        f"{BASE_URL}/policy-documents/{existing_doc_id}",
        json=payload,
        headers=headers,
    )
    assert resp.status_code == 403, f"Expected 403, got {resp.status_code}"
